<?php	$opentime = floor((time() - strtotime("01-Jan-2014"))/86400)>= 0 ? true : false;	# Удаляем просроченные подарки	$db->sql('DELETE FROM `presents_gived` WHERE `godnost`>0 and `godnost`<'.tme().' ;');	# Удаляем подарки	if ( isset($http->get['delpr']) )	{		$exp = explode('_',$http->get['delpr']);		$uid = intval($exp[1]);		$date = intval($exp[0]);		$db->sql("DELETE FROM `presents_gived` WHERE `uid`=".UID." and `date`=".$date);	}	# Открываем подарки	if ( isset($http->get['open']) and $opentime==true)	{		$arr_pr = Array('', 'новогоднем подарке', 'подарке к 8 Марту', 'подарки к 1 Мая', 'новогоднем подарке');		$exp = explode('_',$http->get['open']);		$date = intval($exp[0]);		$p = $db->sqla("SELECT `date`,`type`,`dop_pres` FROM `presents_gived` WHERE `uid`=".UID." and `date`=".$date." and `type`>0 LIMIT 1;");		if ($p==true and $p['dop_pres']>0)		{			$pri = '';			if ($p['type']==1)			{				$v = $db->sqla('SELECT `id`,`name` FROM `weapons` WHERE `id`='.$p['dop_pres'].' LIMIT 1;');				if ($v==true)				{					insert_wp($v['id'],UID);					$pri = $v['name'];				}			} elseif ($p['type']==2)			{				$player->pers['money']+=$p['dop_pres'];				set_vars('`money`=money+'.$p['dop_pres'],UID);				$pri = $p['dop_pres'].' LN';			}elseif ($p['type']==3)			{				$player->pers['dmoney']+=$p['dop_pres'];				set_vars('`dmoney`=dmoney+'.$p['dop_pres'],UID);				$pri = $p['dop_pres'].' Бр.';			}			say_to_chat('s', 'Вы обнаружили <b>'.$pri.'</b> в '.$arr_pr[4].'!', 1, $player->pers['user'], '*', 0); 		}		$db->sql('UPDATE `presents_gived` SET `type`=0 WHERE `uid`='.UID.' and `date`='.$p['date'].' ;');	}		echo "<script>";	$count_prs = $db->sqlr("SELECT COUNT(*) FROM `presents_gived` WHERE `uid`=".$player->pers["uid"],0);	echo "var prs = [".$count_prs."";	$prs = $db->sql("SELECT * FROM `presents_gived` WHERE `uid`=".$player->pers["uid"]);	while ($p = mysql_fetch_assoc($prs))	{		$tp = ($opentime==true) ? $p['type'] : 0;		$who = $p['who'];		if ($p['anonymous']) $who = 'Анонимно';		echo ",['".$p['name']."','".$p['image']."','".$who."','".date('d.m.Y H:i',$p['date'])."','".$p['text']."','".$p['date'].'_'.$player->pers['uid']."',".$tp.",'".date('d.m.Y',$p['godnost'])."']";	}	echo "];show_presents();";	echo "</script>";?>